// Extract uploaded file and validate
const items = $input.all();

// Get the webhook body
const body = items[0].json.body || items[0].json;
const headers = items[0].json.headers || {};

// Initialize result
let result = {
  status: 'error',
  message: '',
  data: null
};

try {
  // Check if file data exists
  if (!body.file) {
    throw new Error('Missing "file" field. Please send: {"file": "base64_string", "filename": "resume.pdf", "user_id": "user123"}');
  }

  // Extract data
  const fileBase64 = body.file;
  const filename = body.filename || 'resume.pdf';
  const userId = body.user_id;

  // Validate user_id
  if (!userId || userId.trim() === '') {
    throw new Error('Missing "user_id" field. Required in request body.');
  }

  // Validate filename extension
  const fileExt = filename.split('.').pop().toLowerCase();
  const allowedExts = ['pdf', 'docx', 'doc'];

  if (!allowedExts.includes(fileExt)) {
    throw new Error(`Invalid file type: .${fileExt}. Allowed: ${allowedExts.join(', ')}`);
  }

  // Validate base64 format (basic check)
  if (!fileBase64 || fileBase64.length < 100) {
    throw new Error('File data too short. Must be valid base64 encoded file.');
  }

  // Check if it looks like base64
  const base64Pattern = /^[A-Za-z0-9+/]+=*$/;
  const sampleCheck = fileBase64.substring(0, 100);
  if (!base64Pattern.test(sampleCheck)) {
    throw new Error('File data does not appear to be valid base64 encoding.');
  }

  // Success - prepare data for next node
  result = {
    status: 'success',
    file_base64: fileBase64,
    filename: filename,
    file_extension: fileExt,
    user_id: userId,
    timestamp: new Date().toISOString()
  };

} catch (error) {
  result.status = 'error';
  result.message = error.message;
}

return [result];

