// Process text from N8N's Extract from File node
const items = $input.all();
const item = items[0].json;

let extractedText = '';
let extractionStatus = 'success';
let errorMsg = null;

try {
  // Extract from File returns text in 'text' field
  if (item.text && typeof item.text === 'string') {
    extractedText = item.text;
  } else if (item.data && typeof item.data === 'string') {
    extractedText = item.data;
  } else if (typeof item === 'string') {
    extractedText = item;
  } else {
    throw new Error('Could not find extracted text');
  }

  // Validate length
  const trimmedText = extractedText.trim();
  if (trimmedText.length < 50) {
    extractionStatus = 'error';
    errorMsg = `Extracted text too short (${trimmedText.length} chars). File may be empty or corrupted.`;
  }

  console.log('Text extracted successfully. Length:', extractedText.length);

} catch (error) {
  extractionStatus = 'error';
  errorMsg = `Error processing extraction: ${error.message}`;
  extractedText = '';
  console.error('Processing error:', error);
}

// IMPORTANT: Preserve ALL previous data
return [{
  json: {
    ...item,  // Keep everything from before
    raw_text: extractedText.trim(),
    extraction_status: extractionStatus,
    extraction_error: errorMsg,
    text_length: extractedText.length
  }
}];

// Parse OpenAI's response and prepare for database
const items = $input.all();
const aiItem = items[0].json;

// Get input data that was passed through
let inputData = aiItem;

let parsedData = null;
let parseStatus = 'success';
let errorMsg = null;

try {
  // Get the AI response - N8N OpenAI node format
  let aiResponse = '';

  // Format: output[0].content[0].text
  if (aiItem.output && Array.isArray(aiItem.output) && aiItem.output[0]) {
    const outputItem = aiItem.output[0];
    if (outputItem.content && Array.isArray(outputItem.content) && outputItem.content[0]) {
      aiResponse = outputItem.content[0].text;
    }
  }

  // Fallback formats
  if (!aiResponse && aiItem.choices && aiItem.choices[0] && aiItem.choices[0].message) {
    aiResponse = aiItem.choices[0].message.content;
  } else if (!aiResponse && aiItem.message && aiItem.message.content) {
    aiResponse = aiItem.message.content;
  } else if (!aiResponse && aiItem.content) {
    aiResponse = aiItem.content;
  } else if (!aiResponse && aiItem.text) {
    aiResponse = aiItem.text;
  }

  if (!aiResponse) {
    throw new Error('Could not find AI response in expected format');
  }

  console.log('Raw AI response length:', aiResponse.length);

  // Clean up response - remove markdown code blocks
  aiResponse = aiResponse.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

  // Find JSON if wrapped in text
  const jsonStart = aiResponse.indexOf('{');
  const jsonEnd = aiResponse.lastIndexOf('}') + 1;

  if (jsonStart >= 0 && jsonEnd > jsonStart) {
    aiResponse = aiResponse.substring(jsonStart, jsonEnd);
  }

  // Parse JSON
  parsedData = JSON.parse(aiResponse);

  // Validate required fields
  if (!parsedData.personal_info || !parsedData.personal_info.full_name) {
    throw new Error('Missing required field: personal_info.full_name');
  }

  // Ensure all expected fields exist
  parsedData = {
    personal_info: parsedData.personal_info || {},
    professional_summary: parsedData.professional_summary || null,
    work_experience: parsedData.work_experience || [],
    education: parsedData.education || [],
    skills: parsedData.skills || { technical: [], soft_skills: [], tools: [], languages: [] },
    certifications: parsedData.certifications || [],
    projects: parsedData.projects || [],
    total_years_experience: parsedData.total_years_experience || 0
  };

  console.log('AI parsing successful');

} catch (error) {
  parseStatus = 'error';
  errorMsg = `Failed to parse AI response: ${error.message}`;
  console.error('Parse error:', error);
  console.error('AI Item structure:', JSON.stringify(aiItem).substring(0, 200));
}

