// Clean data before inserting to Supabase
  // Remove null bytes and other problematic characters

  function cleanText(text) {
    if (typeof text !== 'string') return text;

    // Remove null bytes and other control characters
    return text
      .replace(/\u0000/g, '') // Remove null bytes
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove other control chars
      .trim();
  }

  function cleanObject(obj) {
    if (typeof obj !== 'object' || obj === null) {
      return cleanText(obj);
    }

    if (Array.isArray(obj)) {
      return obj.map(item => cleanObject(item));
    }

    const cleaned = {};
    for (const [key, value] of Object.entries(obj)) {
      if (typeof value === 'string') {
        cleaned[key] = cleanText(value);
      } else if (typeof value === 'object' && value !== null) {
        cleaned[key] = cleanObject(value);
      } else {
        cleaned[key] = value;
      }
    }
    return cleaned;
  }

  // Get the input data
  const items = $input.all();

  // Clean all items
  const cleanedItems = items.map(item => ({
    json: cleanObject(item.json),
    binary: item.binary
  }));

  return cleanedItems;

// Get the input item
  const item = $input.all()[0].json;                                                                                                    
  // Parse structured_data if it's a string                                                                                          
  let structuredData;
  try {
    structuredData = item.structured_data;
    if (typeof structuredData === 'string') {
      structuredData = JSON.parse(structuredData);
    }
  } catch (error) {
    structuredData = {};
  }

  // Safely get arrays or default to empty
  const workExperience = structuredData?.work_experience || [];
  const education = structuredData?.education || [];
  const projects = structuredData?.projects || [];
  const certifications = structuredData?.certifications || [];
  const skills = structuredData?.skills || {};

  const response = {
    success: true,
    message: 'Resume uploaded and parsed successfully',
    data: {
      resume_id: item.id,
      user_id: item.user_id,
      filename: item.original_filename,
      status: item.status,
      parsed_preview: {
        name: structuredData?.personal_info?.full_name || 'Not found',
        email: structuredData?.personal_info?.email || 'Not found',
        phone: structuredData?.personal_info?.phone || 'Not found',
        location: structuredData?.personal_info?.location || 'Not found',
        summary: structuredData?.professional_summary || '',
        work_history: workExperience.map(exp => ({
          position: exp.title || exp.position || '',
          company: exp.company || '',
          location: exp.location || '',
          start_date: exp.start_date || '',
          end_date: exp.end_date || '',
          description: Array.isArray(exp.responsibilities) ? exp.responsibilities.join('\n') : (exp.description || '')
        })),
        education: education.map(edu => ({
          institution: edu.institution || '',
          degree: edu.degree || '',
          field: edu.field_of_study || '',
          graduation_date: edu.graduation_date || ''
        })),
        technical_skills: [
          ...(skills.technical || []),
          ...(skills.tools || []),
          ...(skills.soft_skills || [])
        ],
        projects: projects.map(proj => ({
          name: proj.name || proj.title || '',
          description: proj.description || '',
          technologies: proj.technologies || proj.tech_stack || [],
          link: proj.link || proj.url || ''
        })),
        certifications: certifications.map(cert => ({
          name: cert.name || cert.title || cert.certification_name || '',
          issuer: cert.issuer || cert.organization || '',
          date: cert.date || cert.issue_date || cert.completed_date || '',
          url: cert.url || cert.credential_url || ''
        })),
        total_experience_years: structuredData?.total_years_experience || 0,
        technical_skills_count: (skills.technical || []).length,
        work_history_count: workExperience.length,
        education_count: education.length,
        certifications_count: certifications.length
      },
      file_url: item.file_url,
      created_at: item.created_at
    }
  };

  return [{ json: response }];

