      status: item.status,
      parsed_preview: {
        name: structuredData?.personal_info?.full_name || 'Not found',
        email: structuredData?.personal_info?.email || 'Not found',
        phone: structuredData?.personal_info?.phone || 'Not found',
        location: structuredData?.personal_info?.location || 'Not found',
        summary: structuredData?.professional_summary || '',
        work_history: workExperience.map(exp => ({
          position: exp.title || exp.position || '',
          company: exp.company || '',
          location: exp.location || '',
          start_date: exp.start_date || '',
          end_date: exp.end_date || '',
          description: Array.isArray(exp.responsibilities) ? exp.responsibilities.join('\n') : (exp.description || '')
        })),
        education: education.map(edu => ({
          institution: edu.institution || '',
          degree: edu.degree || '',
          field: edu.field_of_study || '',
          graduation_date: edu.graduation_date || ''
        })),
        technical_skills: [
          ...(skills.technical || []),
          ...(skills.tools || []),
          ...(skills.soft_skills || [])
        ],
        projects: projects.map(proj => ({
          name: proj.name || proj.title || '',
          description: proj.description || '',
          technologies: proj.technologies || proj.tech_stack || [],
          link: proj.link || proj.url || ''
        })),
        certifications: certifications.map(cert => ({
          name: cert.name || cert.title || cert.certification_name || '',
          issuer: cert.issuer || cert.organization || '',
          date: cert.date || cert.issue_date || cert.completed_date || '',
          url: cert.url || cert.credential_url || ''
        })),
        total_experience_years: structuredData?.total_years_experience || 0,
        technical_skills_count: (skills.technical || []).length,
        work_history_count: workExperience.length,
        education_count: education.length,
        certifications_count: certifications.length
      },
      file_url: item.file_url,
      created_at: item.created_at
    }
  };

  return [{ json: response }];
